// PATCH: Add local duplicate-charge clustering from transaction self-joins.

type duplicateTransaction struct {
	ID     string  `json:"id"`
	Payee  string  `json:"payee"`
	Amount float64 `json:"amount"`
	Date   string  `json:"date"`
}

type duplicateCluster struct {
	ClusterID    string                 `json:"cluster_id"`
	Transactions []duplicateTransaction `json:"transactions"`
	ClusterSize  int                    `json:"cluster_size"`
}

func newTransactionsDuplicatesCmd(flags *rootFlags) *cobra.Command {
	var windowDays int
	var tolerance float64
	var minClusterSize int
	var dbPath string

	cmd := &cobra.Command{
		Use:         "duplicates",
		Short:       "Find near-duplicate local transactions",
		Annotations: map[string]string{"mcp:read-only": "true"},
		Example: strings.Trim(`
  # Find candidate duplicate charges within three days and one dollar
  lunch-money-pp-cli transactions duplicates --window 3 --tolerance 1.00 --json
  `, "\n"),
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				return nil
			}
			if windowDays < 0 || tolerance < 0 || minClusterSize < 2 {
				return usageErr(fmt.Errorf("--window and --tolerance must be non-negative; --min-cluster-size must be at least 2"))
			}
			db, err := openLocalStore(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("transactions duplicates: %w", err)
			}
			defer db.Close()
			txs, err := loadLocalTransactions(cmd.Context(), db)
			if err != nil {
				return fmt.Errorf("transactions duplicates: %w", err)
			}
			results := buildDuplicateClusters(txs, windowDays, tolerance, minClusterSize)
			w := cmd.OutOrStdout()
			if flags.asJSON {
				return json.NewEncoder(w).Encode(results)
			}
			fmt.Fprintln(w, "Cluster ID\tCluster Size\tTransaction ID\tPayee\tAmount\tDate")
			for _, cluster := range results {
				for _, tx := range cluster.Transactions {
					fmt.Fprintf(w, "%s\t%d\t%s\t%s\t%.2f\t%s\n",
						cluster.ClusterID, cluster.ClusterSize, tx.ID, tx.Payee, tx.Amount, tx.Date)
				}
			}
			return nil
		},
	}

	cmd.Flags().IntVar(&windowDays, "window", 3, "Date window in days")
	cmd.Flags().Float64Var(&tolerance, "tolerance", 1.00, "Amount tolerance")
	cmd.Flags().IntVar(&minClusterSize, "min-cluster-size", 2, "Minimum cluster size")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path")
	return cmd
}

func buildDuplicateClusters(txs []localTransaction, windowDays int, tolerance float64, minClusterSize int) []duplicateCluster {
	groups := map[string][]int{}
	for i, tx := range txs {
		if tx.PayeeNormalized != "" && !tx.Date.IsZero() && duplicateCountsTransaction(tx) {
			groups[tx.PayeeNormalized] = append(groups[tx.PayeeNormalized], i)
		}
	}
	uf := newUnionFind(len(txs))
	for _, idxs := range groups {
		for i := 0; i < len(idxs); i++ {
			for j := i + 1; j < len(idxs); j++ {
				a, b := txs[idxs[i]], txs[idxs[j]]
				if math.Abs(a.Amount-b.Amount) <= tolerance && absDateDays(a, b) <= windowDays {
					uf.union(idxs[i], idxs[j])
				}
			}
		}
	}

	byRoot := map[int][]localTransaction{}
	for i, tx := range txs {
		if !duplicateCountsTransaction(tx) {
			continue
		}
		root := uf.find(i)
		byRoot[root] = append(byRoot[root], tx)
	}
	clusters := make([]duplicateCluster, 0)
	for _, group := range byRoot {
		if len(group) < minClusterSize {
			continue
		}
		sort.SliceStable(group, func(i, j int) bool {
			if group[i].Date.Equal(group[j].Date) {
				return group[i].ID < group[j].ID
			}
			return group[i].Date.Before(group[j].Date)
		})
		rows := make([]duplicateTransaction, 0, len(group))
		for _, tx := range group {
			rows = append(rows, duplicateTransaction{ID: tx.ID, Payee: tx.Payee, Amount: tx.Amount, Date: tx.DateString})
		}
		clusters = append(clusters, duplicateCluster{Transactions: rows, ClusterSize: len(rows)})
	}
	sort.SliceStable(clusters, func(i, j int) bool {
		return clusters[i].Transactions[0].Date > clusters[j].Transactions[0].Date
	})
	for i := range clusters {
		clusters[i].ClusterID = fmt.Sprintf("dup-%d", i+1)
	}
	return clusters
}

func absDateDays(a, b localTransaction) int {
	days := int(a.Date.Sub(b.Date).Hours() / 24)
	if days < 0 {
		return -days
	}
	return days
}

func duplicateCountsTransaction(tx localTransaction) bool {
	// PATCH(exclude-status): same rule the budget burn and subscription
	// filters apply — excluded transactions should not show up as duplicate
	// candidates.
	if strings.EqualFold(tx.Status, "exclude") || strings.EqualFold(tx.Status, "excluded") {
		return false
	}
	return tx.GroupParentID == "" && tx.SplitParentID == "" && !tx.IsGroupParent && !tx.IsSplitParent
}

type unionFind struct {
	parent []int
	rank   []int
}

func newUnionFind(n int) *unionFind {
	parent := make([]int, n)
	for i := range parent {
		parent[i] = i
	}
	return &unionFind{parent: parent, rank: make([]int, n)}
}

func (u *unionFind) find(x int) int {
	if u.parent[x] != x {
		u.parent[x] = u.find(u.parent[x])
	}
	return u.parent[x]
}

func (u *unionFind) union(a, b int) {
	ra, rb := u.find(a), u.find(b)
	if ra == rb {
		return
	}
	if u.rank[ra] < u.rank[rb] {
		u.parent[ra] = rb
		return
	}
	u.parent[rb] = ra
	if u.rank[ra] == u.rank[rb] {
		u.rank[ra]++
	}
}
